import { useState, useEffect } from 'react';
import { coursesService } from '../../services/courses';
import CourseCard from './CourseCard';
import './CourseList.css';

const CourseList = ({ filters = {} }) => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [pagination, setPagination] = useState({
    count: 0,
    next: null,
    previous: null,
  });

  useEffect(() => {
    loadCourses();
  }, [filters]);

  const loadCourses = async (url = null) => {
    try {
      setLoading(true);
      const params = url ? {} : { ...filters };
      const response = url
        ? await coursesService.getAll({ url })
        : await coursesService.getAll(params);
      
      setCourses(response.results || response);
      if (response.count !== undefined) {
        setPagination({
          count: response.count,
          next: response.next,
          previous: response.previous,
        });
      }
    } catch (err) {
      setError('Failed to load courses');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading courses...</div>;
  }

  if (error) {
    return <div className="error-message">{error}</div>;
  }

  return (
    <div className="course-list">
      <div className="courses-grid">
        {courses.map((course) => (
          <CourseCard key={course.id} course={course} />
        ))}
      </div>
      {courses.length === 0 && (
        <div className="no-courses">No courses found.</div>
      )}
      {(pagination.next || pagination.previous) && (
        <div className="pagination">
          <button
            onClick={() => loadCourses(pagination.previous)}
            disabled={!pagination.previous}
            className="btn btn-secondary"
          >
            Previous
          </button>
          <span>
            Page {Math.floor((pagination.count - courses.length) / 20) + 1} of{' '}
            {Math.ceil(pagination.count / 20)}
          </span>
          <button
            onClick={() => loadCourses(pagination.next)}
            disabled={!pagination.next}
            className="btn btn-secondary"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

export default CourseList;
